mapper.select:
select order_id, request_id, from_user_id, to_user_id, amount, status, remark, create_time, update_time
from transfer_order
where request_id = #{requestId}

select order_id, request_id, from_user_id, to_user_id, amount, status, remark, create_time, update_time
from transfer_order
where from_user_id = #{fromUserId, jdbcType=BINARY}
  and request_id = #{requestId}

mapper.update:
update transfer_order
set status = #{toStatus},
    update_time = current_timestamp
where from_user_id = #{fromUserId, jdbcType=BINARY}
  and request_id = #{requestId}
  and status = #{fromStatus}
